        { "option": "No-code MVP first", "tradeoff": "Faster validation but limited functionality vs delayed launch with full features" },
        { "option": "Wait for co-founder", "tradeoff": "Better product but risk of never starting vs quick market entry" }
      ],
      "recommendation": "Start with no-code MVP immediately - traction will help you find a better co-founder and validate the concept",
      "deadline": "Week 1"
    },
    {
      "priority": "important",
      "question": "Should you focus on a specific creator niche initially?",
      "options": [
        { "option": "Focus on fitness creators", "tradeoff": "Easier to dominate niche vs smaller initial market" },
        { "option": "Stay generalist", "tradeoff": "Larger market but harder to differentiate" }
      ],
      "recommendation": "Focus on fitness creators - they have clear product needs, strong communities, and you can build niche-specific features",
      "deadline": "Week 4"
    },
    {
      "priority": "important",
      "question": "How much equity should you offer a technical co-founder?",
      "options": [
        { "option": "20-25% equity", "tradeoff": "May not attract top talent vs preserving founder ownership" },
        { "option": "30-40% equity", "tradeoff": "Better talent attraction vs significant dilution" }
      ],
      "recommendation": "Offer 25-30% with vesting - you bring domain expertise and initial validation, they bring technical execution",
      "deadline": "Week 6"
    }
  ],
